CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE IF NOT EXISTS users(id UUID PRIMARY KEY DEFAULT gen_random_uuid(), email TEXT UNIQUE NOT NULL, password_hash TEXT NOT NULL, name TEXT DEFAULT 'Admin', created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS settings(key TEXT PRIMARY KEY, value TEXT NOT NULL DEFAULT '');
CREATE TABLE IF NOT EXISTS budget_years(id UUID PRIMARY KEY DEFAULT gen_random_uuid(), year INT UNIQUE NOT NULL, active BOOLEAN DEFAULT TRUE, notes TEXT DEFAULT '', created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS packages(id UUID PRIMARY KEY DEFAULT gen_random_uuid(), year_id UUID REFERENCES budget_years(id) ON DELETE CASCADE, name TEXT NOT NULL, subtitle TEXT DEFAULT '', base_people INT NOT NULL DEFAULT 50, base_price NUMERIC(12,2) NOT NULL DEFAULT 0, card_price NUMERIC(12,2), additional_price NUMERIC(12,2) NOT NULL DEFAULT 0, duration TEXT DEFAULT '', availability TEXT DEFAULT '', included TEXT DEFAULT '', rules TEXT DEFAULT '', featured BOOLEAN DEFAULT FALSE, active BOOLEAN DEFAULT TRUE, sort_order INT DEFAULT 0, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS leads(id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, whatsapp TEXT NOT NULL, birthday_name TEXT, birthday_age TEXT, event_date DATE, guests INT DEFAULT 0, event_type TEXT, wants_food TEXT, selected_package_id UUID REFERENCES packages(id) ON DELETE SET NULL, year INT, base_value NUMERIC(12,2), additional_guests INT, additional_total NUMERIC(12,2), total NUMERIC(12,2), notes TEXT DEFAULT '', status TEXT DEFAULT 'novo', created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS banners(id UUID PRIMARY KEY DEFAULT gen_random_uuid(), title TEXT NOT NULL, subtitle TEXT DEFAULT '', button_text TEXT DEFAULT '', button_link TEXT DEFAULT '', image_url TEXT DEFAULT '', active BOOLEAN DEFAULT TRUE, sort_order INT DEFAULT 0, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS promotions(id UUID PRIMARY KEY DEFAULT gen_random_uuid(), title TEXT NOT NULL, description TEXT DEFAULT '', button_text TEXT DEFAULT 'Participar', link TEXT DEFAULT '', image_url TEXT DEFAULT '', starts_at DATE, ends_at DATE, active BOOLEAN DEFAULT TRUE, highlight BOOLEAN DEFAULT FALSE, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS testimonials(id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, description TEXT DEFAULT '', message TEXT NOT NULL, active BOOLEAN DEFAULT TRUE, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS gallery(id UUID PRIMARY KEY DEFAULT gen_random_uuid(), title TEXT DEFAULT '', image_url TEXT NOT NULL, active BOOLEAN DEFAULT TRUE, sort_order INT DEFAULT 0, created_at TIMESTAMPTZ DEFAULT now());
